// Auto-generated — packed bitmask weight ROM
// 10 neurons × 64 inputs, 465/640 non-zero (72.7%)
// Address: {neuron_idx[3:0], input_idx[6:0]}
module weight_rom_out (
    input  wire [3:0] neuron_idx,
    input  wire [6:0] input_idx,
    output wire signed [1:0] weight
);

    // Packed bitmasks: bit=1 where weight is +1 or -1
    localparam [2047:0] POS_MASK = 2048';
    localparam [2047:0] NEG_MASK = 2048';

    wire [10:0] addr = {neuron_idx, input_idx};
    wire is_pos = POS_MASK[addr];
    wire is_neg = NEG_MASK[addr];

    assign weight = is_pos ? 2'sd1 : is_neg ? -2'sd1 : 2'sd0;

endmodule
